input.old_string:
try:
    c = subprocess.Popen(f'{editor} "{filename}"', env=environ, shell=True)
    exit_code = c.wait()
    if exit_code != 0:
        raise ClickException(
            _("{editor}: Editing failed").format(editor=editor)
        )
except OSError as e:
    raise ClickException(
        _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
    ) from e

input.new_string:
try:
    c = subprocess.Popen(
        f'{editor} "{filename}"',
        env=environ,
        shell=True,
        cwd=self.working_dir,
    )
    try:
        exit_code = c.wait(timeout=self.timeout)
    except subprocess.TimeoutExpired:
        c.terminate()
        c.wait()
        raise ClickException(
            _("{editor}: Editing timed out after {timeout} seconds").format(
                editor=editor, timeout=self.timeout
            )
        ) from None
    if exit_code != 0:
        raise ClickException(
            _("{editor}: Editing failed").format(editor=editor)
        )
except OSError as e:
    raise ClickException(
        _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
    ) from e

